31 | /**
32 |  * EclipseプロジェクトのソースファイルをMavenの標準ディレクトリ構造にコピーするクラス。
33 |  *
34 |  * <ul>
35 |  *   <li>Javaソース (.java) → src/main/java/ または src/test/java/</li>
36 |  *   <li>リソースファイル (非.java) → src/main/resources/ または src/test/resources/</li>
37 |  *   <li>Webコンテンツ (WTPプロジェクトの場合) → src/main/webapp/</li>
38 |  * </ul>
39 |  *
40 |  * <p>{@code convertToUtf8} が {@code true} の場合、以下の変換を行う：</p>
41 |  * <ul>
42 |  *   <li>{@code .java} ファイル: {@code sourceEncoding} で読み込み、UTF-8 で書き出す</li>
43 |  *   <li>{@code .properties} ファイル: {@code sourceEncoding} で読み込み、Unicode エスケープを
44 |  *       Unicode 文字に展開して UTF-8 で書き出す。{@code effectiveTargetVersion <= 8} の場合は
45 |  *       {@code src/main/resources-utf8/} へ出力する</li>
46 |  *   <li>{@code .jsp} ファイル: {@code pageEncoding} 属性を検出してそのエンコードで読み込み、
47 |  *       属性値を {@code UTF-8} に書き換えて出力する</li>
48 |  * </ul>
49 |  */
50 | public class ProjectCopier {
51 | 
52 |     private static final Logger log = AppLogger.get(ProjectCopier.class);
53 | 
54 |     private ProjectCopier() {}
55 | 
56 |     /** ISO-8859-1 でプリアンブルを読む際のバッファサイズ（4KB）。 */
57 |     private static final int JSP_PREAMBLE_BYTES = 4096;
58 | 
59 |     /** JSP の pageEncoding 属性を検出する正規表現。 */
60 |     private static final Pattern JSP_PAGE_ENCODING_PATTERN =
61 |             Pattern.compile("<%@\\s*page\\b[^%]*\\bpageEncoding\\s*=\\s*[\"']([^\"']+)[\"']",
62 |                     Pattern.DOTALL);
63 | 
64 |     /** properties ファイルの Unicode エスケープシーケンスを検出する正規表現。 */
65 |     private static final Pattern UNICODE_ESCAPE_PATTERN =
66 |             Pattern.compile("\\\\u([0-9a-fA-F]{4})");
67 | 
68 |     /**
69 |      * EclipseプロジェクトのファイルをMaven標準ディレクトリ構造にコピーする。
70 |      *
71 |      * @param eclipseProject        パース済みEclipseプロジェクト情報
72 |      * @param dependencies          解決済み依存関係リスト（system スコープの JAR を libs/ にコピーする）
73 |      * @param inputDir              Eclipseプロジェクトのルートディレクトリ
74 |      * @param outputDir             Mavenプロジェクトの出力ルートディレクトリ
75 |      * @param convertToUtf8         true の場合はエンコーディング変換を行う
76 |      * @param sourceEncoding        変換元エンコーディング（convertToUtf8=false の場合は無視）
77 |      * @param effectiveTargetVersion 実効Javaターゲットバージョン（.properties 出力先の判定に使用）
78 |      * @throws IOException ファイルコピーに失敗した場合
79 |      */
80 |     public static void copy(EclipseProject eclipseProject, List<MavenDependency> dependencies,
81 |                             Path inputDir, Path outputDir,
82 |                             boolean convertToUtf8, Charset sourceEncoding,
83 |                             JavaVersion effectiveTargetVersion) throws IOException {
84 | 
85 |         // Javaソースフォルダのコピー
86 |         List<String> sourceFolders = eclipseProject.sourceFolders();
87 |         for (String sourceFolder : sourceFolders) {
88 |             Path srcPath = resolveSourcePath(inputDir, sourceFolder);
89 |             if (!Files.isDirectory(srcPath)) {
90 |                 log.warn("  [WARN] ソースフォルダが見つかりません: {}", srcPath);
91 |                 continue;
92 |             }
93 |             boolean isTest = isTestFolder(sourceFolder);
94 |             Path javaDestBase = outputDir.resolve(isTest ? "src/test/java" : "src/main/java");
95 |             // .properties の出力先: Java 9+ → src/main/resources/、Java 8以下 → src/main/resources-utf8/
96 |             boolean useUtf8ResourceDir = convertToUtf8 && !effectiveTargetVersion.isUnknown()
97 |                     && effectiveTargetVersion.compareTo(JavaVersion.Java8) <= 0;
98 |             Path resourceDestBase = outputDir.resolve(
99 |                     isTest ? "src/test/resources"
100 |                            : (useUtf8ResourceDir ? "src/main/resources-utf8" : "src/main/resources"));
101 |             Path resourceDestNormal = outputDir.resolve(isTest ? "src/test/resources" : "src/main/resources");
102 | 
103 |             copySourceFolder(srcPath, srcPath, javaDestBase, resourceDestBase, resourceDestNormal,
104 |                     convertToUtf8, sourceEncoding);
105 |         }
106 | 
107 |         // Webコンテンツのコピー（WTPプロジェクトの場合）
108 |         if (eclipseProject.webProject() && eclipseProject.webContentRoot() != null) {
109 |             Path webContentPath = resolveSourcePath(inputDir, eclipseProject.webContentRoot());
110 |             if (Files.isDirectory(webContentPath)) {
111 |                 Path webappDest = outputDir.resolve("src/main/webapp");
112 |                 copyWebContents(webContentPath, webappDest, convertToUtf8, sourceEncoding);
113 |                 log.info("  Copied web content: {} → {}", webContentPath, webappDest);
114 |             } else {
115 |                 log.warn("  [WARN] Webコンテンツルートが見つかりません: {}", webContentPath);
116 |             }
117 |         }
118 | 
119 |         // system スコープの JAR を libs/ にコピー
120 |         for (MavenDependency dep : dependencies) {
121 |             if ("system".equals(dep.scope()) && dep.systemPath() != null) {
122 |                 Path src = Path.of(dep.systemPath());
123 |                 if (Files.isRegularFile(src)) {
124 |                     Path libsDir = outputDir.resolve("libs");
125 |                     Files.createDirectories(libsDir);
126 |                     Path dest = libsDir.resolve(src.getFileName());
127 |                     Files.copy(src, dest, StandardCopyOption.REPLACE_EXISTING);
128 |                     log.debug("  Copied JAR to libs/: {}", dest.getFileName());
129 |                 }
130 |             }
131 |         }
132 |     }
133 | 
134 |     /**
135 |      * ソースフォルダ内のファイルを.javaとリソースに振り分けてコピーする。
136 |      *
137 |      * @param baseDir            コピー元のルート（相対パス計算の基点）
138 |      * @param currentDir         現在処理中のディレクトリ
139 |      * @param javaDestBase       .javaファイルのコピー先ベースディレクトリ
140 |      * @param resourceDest       リソースファイルのコピー先ベースディレクトリ（.properties はここへ）
141 |      * @param resourceDestNormal 通常のリソースコピー先（.properties 以外の非.javaファイルはここへ）
142 |      * @param convertToUtf8      true の場合はエンコーディング変換を行う
143 |      * @param sourceEncoding     変換元エンコーディング
144 |      * @throws IOException ファイルコピーに失敗した場合
145 |      */
146 |     private static void copySourceFolder(Path baseDir, Path currentDir, Path javaDestBase,
147 |                                          Path resourceDest, Path resourceDestNormal,
148 |                                          boolean convertToUtf8, Charset sourceEncoding)
149 |             throws IOException {
150 |         Files.walk(currentDir)
151 |                 .filter(Files::isRegularFile)
152 |                 .forEach(srcFile -> {
153 |                     try {
154 |                         Path relative = baseDir.relativize(srcFile);
155 |                         String fileName = srcFile.getFileName().toString();
156 |                         boolean isJava = fileName.endsWith(".java");
157 |                         boolean isProperties = fileName.endsWith(".properties");
158 | 
159 |                         if (isJava) {
160 |                             Path destFile = javaDestBase.resolve(relative);
161 |                             Files.createDirectories(destFile.getParent());
162 |                             if (convertToUtf8) {
163 |                                 copyWithEncodingConversion(srcFile, destFile, sourceEncoding);
164 |                                 log.debug("  [Java:UTF-8変換] {}", relative);
165 |                             } else {
166 |                                 Files.copy(srcFile, destFile, StandardCopyOption.REPLACE_EXISTING);
167 |                                 log.debug("  [バイナリコピー] {}", relative);
168 |                             }
169 |                         } else if (isProperties && convertToUtf8) {
170 |                             // .properties: Unicode エスケープ展開 + UTF-8 で resourceDest へ
171 |                             Path destFile = resourceDest.resolve(relative);
172 |                             Files.createDirectories(destFile.getParent());
173 |                             copyPropertiesWithConversion(srcFile, destFile, sourceEncoding);
174 |                             log.debug("  [Properties:UTF-8変換] {}", relative);
175 |                         } else {
176 |                             // その他のリソース（バイナリコピー）
177 |                             Path destFile = resourceDestNormal.resolve(relative);
178 |                             Files.createDirectories(destFile.getParent());
179 |                             Files.copy(srcFile, destFile, StandardCopyOption.REPLACE_EXISTING);
180 |                             log.debug("  [バイナリコピー] {}", relative);
181 |                         }
182 |                     } catch (IOException e) {
183 |                         throw new RuntimeException("ファイルコピーに失敗しました: " + srcFile, e);
184 |                     }
185 |                 });
186 |         log.info("  Copied source folder: {} → {}", currentDir, javaDestBase);
187 |     }
188 | 
189 |     /**
190 |      * Webコンテンツディレクトリを再帰的にコピーする。
191 |      * WEB-INF/lib 直下の .jar ファイルはスキップする。
192 |      * {@code convertToUtf8=true} の場合、.jsp ファイルはエンコーディング変換を行う。
193 |      *
194 |      * @param srcDir         コピー元ディレクトリ
195 |      * @param destDir        コピー先ディレクトリ
196 |      * @param convertToUtf8  true の場合はエンコーディング変換を行う
197 |      * @param sourceEncoding 変換元エンコーディング（.jsp の pageEncoding が不明な場合に使用）
198 |      * @throws IOException ファイルコピーに失敗した場合
199 |      */
200 |     private static void copyWebContents(Path srcDir, Path destDir,
201 |                                         boolean convertToUtf8, Charset sourceEncoding)
202 |             throws IOException {
203 |         Path excludeJarDir = srcDir.resolve("WEB-INF/lib");
204 |         Files.walk(srcDir)
205 |                 .filter(srcPath -> !srcPath.startsWith(excludeJarDir)
206 |                         || !srcPath.getFileName().toString().endsWith(".jar"))
207 |                 .forEach(srcPath -> {
208 |                     try {
209 |                         Path relative = srcDir.relativize(srcPath);
210 |                         Path destPath = destDir.resolve(relative);
211 |                         if (Files.isDirectory(srcPath)) {
212 |                             Files.createDirectories(destPath);
213 |                             log.debug("  [ディレクトリー作成] {}", relative);
214 |                         } else {
215 |                             Files.createDirectories(destPath.getParent());
216 |                             String fileName = srcPath.getFileName().toString();
217 |                             if (convertToUtf8 && fileName.endsWith(".jsp")) {
218 |                                 Charset jspEncoding = extractJspPageEncoding(srcPath, sourceEncoding);
219 |                                 if (jspEncoding != null) {
220 |                                     copyJspWithConversion(srcPath, destPath, jspEncoding);
221 |                                     log.debug("  [JSP:UTF-8変換] {} (encode={})", relative, jspEncoding);
222 |                                 } else {
223 |                                     // pageEncoding が既に UTF-8 → バイナリコピー
224 |                                     Files.copy(srcPath, destPath, StandardCopyOption.REPLACE_EXISTING);
225 |                                     log.debug("  [バイナリコピー] {}", relative);
226 |                                 }
227 |                             } else {
228 |                                 Files.copy(srcPath, destPath, StandardCopyOption.REPLACE_EXISTING);
229 |                                 log.debug("  [バイナリコピー] {}", relative);
230 |                             }
231 |                         }
232 |                     } catch (IOException e) {
233 |                         throw new RuntimeException("ファイルコピーに失敗しました: " + srcPath, e);
234 |                     }
235 |                 });
236 |     }
237 | 
238 |     /**
239 |      * テキストファイルを指定エンコードで読み込み、UTF-8 で書き出す。
240 |      *
241 |      * @param src  コピー元ファイル
242 |      * @param dest コピー先ファイル
243 |      * @param from 変換元エンコーディング
244 |      * @throws IOException ファイル読み書きに失敗した場合
245 |      */
246 |     static void copyWithEncodingConversion(Path src, Path dest, Charset from) throws IOException {
247 |         String content = Files.readString(src, from);
248 |         Files.writeString(dest, content, StandardCharsets.UTF_8);
249 |     }
250 | 
251 |     /**
252 |      * .properties ファイルを指定エンコードで読み込み、Unicode エスケープを展開して UTF-8 で書き出す。
253 |      *
254 |      * @param src  コピー元ファイル
255 |      * @param dest コピー先ファイル
256 |      * @param from 変換元エンコーディング
257 |      * @throws IOException ファイル読み書きに失敗した場合
258 |      */
259 |     static void copyPropertiesWithConversion(Path src, Path dest, Charset from) throws IOException {
260 |         List<String> lines = Files.readAllLines(src, from);
261 |         List<String> converted = lines.stream()
262 |                 .map(ProjectCopier::unescapeUnicode)
263 |                 .toList();
264 |         Files.write(dest, converted, StandardCharsets.UTF_8);
265 |     }
266 | 
267 |     /**
268 |      * 文字列中の Unicode エスケープシーケンス（&#92;uXXXX 形式）を Unicode 文字に展開する。
269 |      *
270 |      * @param line 入力文字列
271 |      * @return Unicode エスケープを展開した文字列
272 |      */
273 |     static String unescapeUnicode(String line) {
274 |         Matcher m = UNICODE_ESCAPE_PATTERN.matcher(line);
275 |         if (!m.find()) {
276 |             return line;
277 |         }
278 |         m.reset();
279 |         StringBuilder sb = new StringBuilder();
280 |         while (m.find()) {
281 |             int codePoint = Integer.parseInt(m.group(1), 16);
282 |             m.appendReplacement(sb, Matcher.quoteReplacement(String.valueOf((char) codePoint)));
283 |         }
284 |         m.appendTail(sb);
285 |         return sb.toString();
286 |     }
287 | 
288 |     /**
289 |      * JSP ファイルの先頭 4KB を ISO-8859-1 で読み込み、{@code pageEncoding} 属性を検出する。
290 |      *
291 |      * <ul>
292 |      *   <li>検出でき、かつ UTF-8 系でない場合: そのエンコーディングの {@link Charset} を返す</li>
293 |      *   <li>検出できない場合: {@code fallback} を返す</li>
294 |      *   <li>検出でき、かつ既に UTF-8 系の場合: {@code null} を返す（呼び出し元でバイナリコピーに切り替える）</li>
295 |      * </ul>
296 |      *
297 |      * @param jspFile  JSP ファイルのパス
298 |      * @param fallback pageEncoding が見つからない場合に返すエンコーディング
299 |      * @return 変換元エンコーディング、または null（既に UTF-8 の場合）
300 |      * @throws IOException ファイル読み込みに失敗した場合
301 |      */
302 |     static Charset extractJspPageEncoding(Path jspFile, Charset fallback) throws IOException {
303 |         // 先頭 4KB を ISO-8859-1 で読み込む（バイト値をそのまま文字として扱うため）
304 |         byte[] bytes = Files.readAllBytes(jspFile);
305 |         int len = Math.min(bytes.length, JSP_PREAMBLE_BYTES);
306 |         String preamble = new String(bytes, 0, len, StandardCharsets.ISO_8859_1);
307 | 
308 |         Matcher m = JSP_PAGE_ENCODING_PATTERN.matcher(preamble);
309 |         if (!m.find()) {
310 |             return fallback;
311 |         }
312 |         String encodingName = m.group(1).trim();
313 |         // 既に UTF-8 系であれば null を返す
314 |         if (encodingName.equalsIgnoreCase("UTF-8") || encodingName.equalsIgnoreCase("UTF8")) {
315 |             return null;
316 |         }
317 |         try {
318 |             return Charset.forName(encodingName);
319 |         } catch (Exception e) {
320 |             // 不明なエンコーディング名の場合は fallback を使用
321 |             log.warn("  [WARN] JSP の pageEncoding が不明です: {} → fallback を使用", encodingName);
322 |             return fallback;
323 |         }
324 |     }
325 | 
326 |     /**
327 |      * JSP ファイルを指定エンコードで読み込み、{@code pageEncoding} 属性値を {@code UTF-8} に書き換えて出力する。
328 |      *
329 |      * @param src  コピー元 JSP ファイル
330 |      * @param dest コピー先ファイル
331 |      * @param from 変換元エンコーディング
332 |      * @throws IOException ファイル読み書きに失敗した場合
333 |      */
334 |     static void copyJspWithConversion(Path src, Path dest, Charset from) throws IOException {
335 |         String content = Files.readString(src, from);
336 |         // pageEncoding 属性値を UTF-8 に書き換える（シングルクォートとダブルクォートの両方に対応）
337 |         String converted = content.replaceAll(
338 |                 "(<%@\\s*page\\b[^%]*\\bpageEncoding\\s*=\\s*)([\"'])([^\"']+)\\2",
339 |                 "$1$2UTF-8$2");
340 |         Files.writeString(dest, converted, StandardCharsets.UTF_8);
341 |     }
342 | 
343 |     /**
344 |      * ソースフォルダのパス文字列をinputDir基点の絶対Pathに解決する。
345 |      * 先頭の '/' は除去して相対パスとして扱う。
346 |      */
347 |     private static Path resolveSourcePath(Path inputDir, String folderPath) {
348 |         String normalized = folderPath.startsWith("/") ? folderPath.substring(1) : folderPath;
349 |         if (normalized.isEmpty()) {
350 |             return inputDir;
351 |         }
352 |         return inputDir.resolve(normalized);
353 |     }
354 | 
355 |     /**
356 |      * ソースフォルダ名に "test" が含まれるかどうかを判定する。
357 |      * パスの各セグメントを小文字で比較する。
358 |      */
359 |     static boolean isTestFolder(String folderPath) {
360 |         String lower = folderPath.toLowerCase();
361 |         for (String segment : lower.split("[/\\\\]")) {
362 |             if (segment.equals("test") || segment.startsWith("test-") || segment.endsWith("-test")) {
363 |                 return true;
364 |             }
365 |         }
366 |         return false;
367 |     }
368 | }
